const CRON_SECRET = process.env.CRON_SECRET

async function enrichPage(slug, data) {
  console.log(`\n=== Enriching: ${slug} ===`)

  const existing = await prisma.comparison.findUnique({
    where: { slug },
    select: { id: true, slug: true, content: true },
  })

  if (!existing) {
    console.warn(`  SKIP: ${slug} not found in DB`)
    return
  }

  const existingContent = (existing.content && typeof existing.content === 'object') ? existing.content : {}

  // Check if already enriched
  if (existingContent.enrichedBy && existingContent.enrichedBy !== 'DAN-2473') {
    console.log(`  SKIP: already enriched by ${existingContent.enrichedBy}`)
    return
  }

  const newContent = {
    ...existingContent,
    expertAnalysis: data.analysis.trim(),
    sources: data.sources,
    enrichedBy: 'DAN-2473',
    reviewedAt: new Date().toISOString(),
    reviewedBy: 'daniel-rozin',
    isHumanReviewed: true,
  }

  await prisma.comparison.update({
    where: { id: existing.id },
    data: {
      content: newContent,
      isHumanReviewed: true,
      contentScore: 85,
      lastRefreshedAt: new Date(),
      updatedAt: new Date(),
    },
  })
  console.log(`  Updated content: expertAnalysis ${data.analysis.length} chars, ${data.sources.length} sources`)

  // Update FAQs
  if (data.faqs && data.faqs.length > 0) {
    await prisma.fAQ.deleteMany({ where: { comparisonId: existing.id } })
    for (const faq of data.faqs) {
      if (faq.question && faq.answer) {
        await prisma.fAQ.create({
          data: { question: faq.question, answer: faq.answer, comparisonId: existing.id },
        })
      }
    }
    console.log(`  FAQs updated: ${data.faqs.length}`)
  }

  // Fire IndexNow
  if (CRON_SECRET) {
    try {
      const res = await fetch('https://www.aversusb.net/api/indexnow', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${CRON_SECRET}` },
        body: JSON.stringify({ slugs: [slug] }),
        signal: AbortSignal.timeout(10000),
      })
      console.log(`  IndexNow: ${res.ok ? 'submitted' : res.status}`)
    } catch (e) {
      console.warn(`  IndexNow failed: ${e.message}`)
    }
  }

  console.log(`  DONE: ${slug}`)
}

async function main() {
  console.log('DAN-2473: Enriching compare pages ranked 581-590 by GSC (Batch 60)\n')

  for (const [slug, data] of Object.entries(NEW_CONTENT)) {
    try {
      await enrichPage(slug, data)
      await new Promise(r => setTimeout(r, 1000))
    } catch (e) {
      console.error(`ERROR: ${slug}:`, e.message)
    }
  }

  console.log('\n=== Summary ===')
  const slugs = Object.keys(NEW_CONTENT)
  for (const slug of slugs) {
    const r = await prisma.comparison.findUnique({
      where: { slug },
      select: { slug: true, content: true },
    })
    const c = r?.content || {}
    console.log(`  ${slug}: enrichedBy=${c.enrichedBy || 'none'}, expertAnalysis=${!!c.expertAnalysis}`)
  }

  await prisma.$disconnect()
  console.log('\nDone.')
}

main().catch(e => { console.error('Fatal:', e); process.exit(1) })
